/**
 * StatCard.jsx
 * ─────────────────────────────────────────────────────────────
 * Tarjeta de estadística reutilizable para el dashboard.
 * Muestra un valor numérico grande con label, tendencia opcional
 * y animación de entrada escalonada.
 *
 * Props:
 *   label     — string  (ej: "Balance total")
 *   value     — string  (ej: "$1.250.000")
 *   subtext   — string  (texto secundario opcional)
 *   trend     — number  (positivo = verde, negativo = rojo)
 *   icon      — string  (emoji o ícono)
 *   variant   — 'default' | 'accent' | 'success' | 'danger'
 *   delay     — number  (índice para animación escalonada)
 *   loading   — boolean
 */

import styles from './StatCard.module.css'

export default function StatCard({
  label,
  value,
  subtext,
  trend,
  icon,
  variant  = 'default',
  delay    = 0,
  loading  = false,
}) {
  const hasTrend  = trend !== undefined && trend !== null
  const isPositive = trend >= 0

  if (loading) {
    return (
      <div className={`card ${styles.card}`}>
        <div className={`skeleton ${styles.skeletonLabel}`} />
        <div className={`skeleton ${styles.skeletonValue}`} />
        <div className={`skeleton ${styles.skeletonSub}`} />
      </div>
    )
  }

  return (
    <div
      className={`card ${styles.card} ${styles[variant]} animate-fade-up delay-${delay}`}
    >
      {/* Encabezado: label + ícono */}
      <div className={styles.header}>
        <span className="label">{label}</span>
        {icon && <span className={styles.icon}>{icon}</span>}
      </div>

      {/* Valor principal — usa fuente serif para elegancia */}
      <div className={`${styles.value} font-display`}>{value}</div>

      {/* Footer: subtexto y tendencia */}
      <div className={styles.footer}>
        {subtext && (
          <span className={styles.subtext}>{subtext}</span>
        )}
        {hasTrend && (
          <span className={`${styles.trend} ${isPositive ? styles.trendUp : styles.trendDown}`}>
            {isPositive ? '↑' : '↓'} {Math.abs(trend)}%
          </span>
        )}
      </div>
    </div>
  )
}
